// Large seed — ≥100 songs per genre across R&B, Hip Hop, Pop, Rock, Country,
// Gospel, Soul, Jazz. Lyric snippets are short memorable hooks used for a
// trivia game (fair-use scope). Uses ON CONFLICT DO NOTHING so it's safe
// to re-run against Postgres / Supabase.

import postgres from "postgres";
import dotenv from "dotenv";
dotenv.config();

// Seeds need a DDL-capable long-lived connection. Prefer Session pooler
// (IPv4-friendly), fall back to Direct (IPv6-only), then legacy DATABASE_URL.
const DB_URL =
  process.env.SUPABASE_SESSION_POOLER_STRING ??
  process.env.SUPABASE_DIRECT_CONNECTION_STRING ??
  process.env.DATABASE_URL;
if (!DB_URL) {
  console.error(
    "Set SUPABASE_SESSION_POOLER_STRING (or SUPABASE_DIRECT_CONNECTION_STRING) in .env"
  );
  process.exit(1);
}

// Compact schema: t title, a artist, p prompt, c completion, y year, g genre,
// d difficulty (low|medium|high), s section (chorus|hook|verse|bridge), x explicit.
const RAW = [];

function add(rows) { for (const r of rows) RAW.push(r); }

// Helper: decade label from year to match schema conventions used in queries.
function decadeOf(y) {
  if (y >= 2020) return "2020–Present";
  const start = Math.floor(y / 10) * 10;
  return `${start}–${start + 10}`;
}

